import dataclasses
import unittest
from pathlib import Path
from unittest import mock

from app import authority
from app.factory import dispatch
from app.outbox import INTENTS
from app.types import Request
from app.worker import HANDLERS, consume
from deploy.settings import REQUIRED, validate
from ops.readiness import ready
from workflow.gateway import command_v2, on_status


ROOT = Path(__file__).resolve().parents[1]


class AuthorityRoutingTest(unittest.TestCase):
    def test_every_request_shape_uses_authority(self):
        requests = (
            Request(),
            Request(domain_context={"tenant": "acme"}),
            *(Request(run_mode=intent) for intent in INTENTS),
        )

        for request in requests:
            with self.subTest(request=request):
                result = dispatch(request)
                self.assertEqual(result["authority"], "v2")

    def test_authority_failure_does_not_reactivate_a_fallback(self):
        with mock.patch.object(
            authority, "submit", side_effect=RuntimeError("authority unavailable")
        ):
            with self.assertRaisesRegex(RuntimeError, "authority unavailable"):
                dispatch(Request(run_mode="execute"))


class RetirementTest(unittest.TestCase):
    def test_planexecution_is_not_part_of_the_request_contract(self):
        self.assertNotIn(
            "planexecution_phase", {field.name for field in dataclasses.fields(Request)}
        )
        with self.assertRaises(TypeError):
            Request(planexecution_phase="running")

    def test_legacy_execution_module_is_absent(self):
        self.assertFalse((ROOT / "app" / "legacy.py").exists())


class WorkflowGatewayTest(unittest.TestCase):
    def test_command_v2_creates_an_outbox_record_for_every_authority_intent(self):
        payload = {"request_id": "req-1"}

        for intent in INTENTS:
            with self.subTest(intent=intent):
                self.assertEqual(
                    command_v2(intent, payload),
                    {"intent": intent, "payload": payload, "status": "pending"},
                )

    def test_command_v2_rejects_unknown_intents(self):
        with self.assertRaisesRegex(ValueError, "unknown"):
            command_v2("unknown", {})

    def test_status_callback_remains_public(self):
        self.assertEqual(on_status({"status": "completed"}), "completed")


class WorkerTest(unittest.TestCase):
    def test_every_authority_intent_has_a_handler(self):
        self.assertEqual(set(HANDLERS), set(INTENTS))

        for intent in INTENTS:
            with self.subTest(intent=intent):
                record = {"intent": intent, "payload": {}, "status": "pending"}
                self.assertEqual(consume(record)["status"], "completed")


class ProductionSafetyTest(unittest.TestCase):
    def setUp(self):
        self.complete_env = {name: f"value-for-{name.lower()}" for name in REQUIRED}

    def test_settings_fail_closed_for_missing_or_empty_values(self):
        self.assertFalse(validate({}))
        for setting in REQUIRED:
            with self.subTest(setting=setting):
                missing = dict(self.complete_env)
                missing.pop(setting)
                self.assertFalse(validate(missing))

                empty = dict(self.complete_env)
                empty[setting] = ""
                self.assertFalse(validate(empty))

        self.assertTrue(validate(self.complete_env))

    def test_readiness_requires_environment_and_all_handlers(self):
        self.assertFalse(ready({}))
        self.assertTrue(ready(self.complete_env))

        with mock.patch.dict(HANDLERS, {}, clear=True):
            self.assertFalse(ready(self.complete_env))

    def test_checked_in_production_environment_is_complete(self):
        env = {}
        for line in (ROOT / "deploy" / "production.env").read_text().splitlines():
            if line and not line.startswith("#"):
                key, value = line.split("=", 1)
                env[key] = value

        self.assertTrue(validate(env))


if __name__ == "__main__":
    unittest.main()
